Perform a comprehensive code review of this API endpoint. Cover: security, performance, error handling, code style, and testability.

```python
import json
from flask import Flask, request

app = Flask(__name__)
users = {}

@app.route('/user', methods=['POST'])
def create_user():
    data = json.loads(request.data)
    users[data['email']] = data
    open('users.log', 'a').write(str(data) + '\n')
    return json.dumps({'status': 'ok', 'user': data})

@app.route('/user/<email>')
def get_user(email):
    return json.dumps(users[email])
